TriggerOraclev10g.body:
DECLARE
    vro_parametros    tkr_parametros%ROWTYPE;
    vro_cita          tkr_citas%ROWTYPE;
    v_cod_error       NUMBER;
    v_mensaje_error   VARCHAR2 (4000);
BEGIN
    IF :new.id IS NULL
    THEN
        :new.id := tkr_citas_seq.NEXTVAL;
        :new.fecha_elaboracion := SYSTIMESTAMP AT TIME ZONE 'America/Bogota';
        :new.envios_recordatorio := 0;
    END IF;

    :new.id_hexadecimal := LTRIM (LTRIM (TO_CHAR (:new.id, '00000000000X')), '0');

    IF :new.fecha_final_cita IS NULL
    THEN
        IF pkgtkr_parametros_dao.f_existe (1, vro_parametros) = TRUE
        THEN
            :new.fecha_final_cita := :new.fecha_inicio_cita + (TO_NUMBER (vro_parametros.valor_parametro) / 1440);
        END IF;
    END IF;

    IF :new.id_estado_cita = 9
    THEN
        :new.id_causa_rc := 9;
    END IF;

    IF :new.id_estado_cita <> :old.id_estado_cita
    THEN
        vro_cita.ID := :new.ID;
        vro_cita.ID_HEXADECIMAL := :new.ID_HEXADECIMAL;
        vro_cita.ID_USUARIO := :new.ID_USUARIO;
        vro_cita.ID_ESTADO_CITA := :new.ID_ESTADO_CITA;
        vro_cita.FECHA_INICIO_CITA := :new.FECHA_INICIO_CITA;
        vro_cita.FECHA_FINAL_CITA := :new.FECHA_FINAL_CITA;
        vro_cita.DESCRIPCION := :new.DESCRIPCION;
        vro_cita.URL_ZOOM := :new.URL_ZOOM;
        vro_cita.CODIGO_ZOOM := :new.CODIGO_ZOOM;
        vro_cita.ID_CLASE_CITA := :new.ID_CLASE_CITA;
        vro_cita.ID_USUARIO_ELABORA := :new.ID_USUARIO_ELABORA;
        vro_cita.MOTIVO_CANCELACION := :new.MOTIVO_CANCELACION;
        vro_cita.ID_USUARIO_CANCELA := :new.ID_USUARIO_CANCELA;
        vro_cita.FECHA_CANCELACION := :new.FECHA_CANCELACION;
        vro_cita.ID_USUARIO_SOLICITA_CANCELA := :new.ID_USUARIO_SOLICITA_CANCELA;
        vro_cita.ESTADO_ENCUESTA := :new.ESTADO_ENCUESTA;
        vro_cita.FECHA_ELABORACION := :new.FECHA_ELABORACION;
        vro_cita.ENVIOS_RECORDATORIO := :new.ENVIOS_RECORDATORIO;
        vro_cita.URL_ZOOM_DOCTOR := :new.URL_ZOOM_DOCTOR;
        vro_cita.ID_CUENTA_ZOOM := :new.ID_CUENTA_ZOOM;
        vro_cita.CLAVE_ZOOM := :new.CLAVE_ZOOM;
        vro_cita.ID_REUNION_ZOOM := :new.ID_REUNION_ZOOM;
        vro_cita.REDIRECT := :new.REDIRECT;
        vro_cita.ORIGEN := :new.ORIGEN;
        vro_cita.INGRESO_PAGAR := :new.INGRESO_PAGAR;
        vro_cita.ID_SOLICITUD_ATENCION := :new.ID_SOLICITUD_ATENCION;
        vro_cita.ID_USO_SUSCRIPCION := :new.ID_USO_SUSCRIPCION;
        vro_cita.MONTO_REFERIDOS := :new.MONTO_REFERIDOS;
        vro_cita.ID_SERVICIO_CLASE := :new.ID_SERVICIO_CLASE;
        vro_cita.ID_CITA_ORIGEN := :new.ID_CITA_ORIGEN;
        vro_cita.ID_ACCESO_CREACION := :new.ID_ACCESO_CREACION;
        vro_cita.ID_ENTIDAD := :new.ID_ENTIDAD;
        vro_cita.ID_CONVENIO := :new.ID_CONVENIO;
        vro_cita.ID_SERVICIO_SOLICITADO := :new.ID_SERVICIO_SOLICITADO;
        vro_cita.FECHA_CREACION := :new.FECHA_CREACION;
        vro_cita.ID_ESPECIALIDAD := :new.ID_ESPECIALIDAD;
        vro_cita.TIPO_CITA := :new.TIPO_CITA;
        vro_cita.ID_SERVICIO := :new.ID_SERVICIO;
        vro_cita.TIEMPO_CITA_ZOOM := :new.TIEMPO_CITA_ZOOM;
        vro_cita.INFO_ZOOM := :new.INFO_ZOOM;
        vro_cita.INFO_GRABACION_ZOOM := :new.INFO_GRABACION_ZOOM;
        vro_cita.ID_DET_LIQUIDACION := :new.ID_DET_LIQUIDACION;
        vro_cita.TRANSCRIPCION := :new.TRANSCRIPCION;
        vro_cita.TIPO_AFILIADO := :new.TIPO_AFILIADO;
        vro_cita.COMENTARIOS := :new.COMENTARIOS;
        vro_cita.TRANSCRIPCION_ZOOM := :new.TRANSCRIPCION_ZOOM;
        vro_cita.COMENTARIOS_FACTURACION := :new.COMENTARIOS_FACTURACION;
        vro_cita.ID_ACTA_MEDICA := :new.ID_ACTA_MEDICA;
        vro_cita.ENTRADA_CLOB := :new.ENTRADA_CLOB;
        vro_cita.FORMA_INGRESO := :new.FORMA_INGRESO;
        vro_cita.ID_PROFESIONAL := :new.ID_PROFESIONAL;
        pkgln_ghl.p_grabar_info_cita (vro_cita, v_cod_error, v_mensaje_error);
        pkgln_ghl.p_grabar_usuario_cita(vro_cita.id_usuario, vro_cita, v_cod_error, v_mensaje_error);
    END IF;
END;
